import React, { useEffect } from 'react';
import { createPortal } from 'react-dom';
import styles from './ReportRowActionMenu.module.css';

export type ReportRowMenuAction =
  | 'viewDocument'
  | 'viewReportDetail'
  | 'refreshData'
  | 'print'
  | 'export'
  | 'chart';

export type ReportRowMenuLabels = {
  viewDocument: string;
  viewReportDetail: string;
  refreshData: string;
  print: string;
  export: string;
  chart: string;
};

export type ReportRowActionMenuProps = {
  open: boolean;
  x: number;
  y: number;
  onClose: () => void;
  onSelect: (action: ReportRowMenuAction) => void;
  labels: ReportRowMenuLabels;
  canOpenDocument: boolean;
  /** Báo cáo có drill-down sang báo cáo chi tiết (vd. Sổ cái → Sổ chi tiết). */
  canViewReportDetail?: boolean;
  /** Xem biểu đồ — ẩn khi config tắt chart hoặc BE không có loại chart (parity toolbar `canChart`). */
  canChart?: boolean;
  testIdPrefix: string;
};

export const ReportRowActionMenu: React.FC<ReportRowActionMenuProps> = ({
  open,
  x,
  y,
  onClose,
  onSelect,
  labels,
  canOpenDocument,
  canViewReportDetail = false,
  canChart = false,
  testIdPrefix,
}) => {
  useEffect(() => {
    if (!open) return;
    const onKey = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [open, onClose]);

  if (!open) return null;

  const clampedY = Math.min(y, window.innerHeight - 320);
  const clampedX = Math.min(x, window.innerWidth - 240);

  const pick = (action: ReportRowMenuAction) => {
    onSelect(action);
    onClose();
  };

  return createPortal(
    <>
      <div
        role="presentation"
        style={{ position: 'fixed', inset: 0, zIndex: 1299 }}
        onMouseDown={onClose}
        data-testid={`${testIdPrefix}-row-menu-backdrop`}
      />
      <div
        className={styles.menu}
        style={{ left: clampedX, top: clampedY }}
        role="menu"
        data-testid={`${testIdPrefix}-row-menu`}
      >
        <button
          type="button"
          className={styles.item}
          role="menuitem"
          disabled={!canOpenDocument}
          onClick={() => pick('viewDocument')}
          data-testid={`${testIdPrefix}-row-menu-view-document`}
        >
          <i className="fas fa-file-invoice" aria-hidden />
          {labels.viewDocument}
        </button>
        {canViewReportDetail ? (
          <button
            type="button"
            className={styles.item}
            role="menuitem"
            onClick={() => pick('viewReportDetail')}
            data-testid={`${testIdPrefix}-row-menu-view-report-detail`}
          >
            <i className="fas fa-list-alt" aria-hidden />
            {labels.viewReportDetail}
          </button>
        ) : null}
        <div className={styles.separator} />
        <button
          type="button"
          className={styles.item}
          role="menuitem"
          onClick={() => pick('refreshData')}
          data-testid={`${testIdPrefix}-row-menu-refresh-data`}
        >
          <i className="fas fa-sync-alt" aria-hidden />
          {labels.refreshData}
        </button>
        <button
          type="button"
          className={styles.item}
          role="menuitem"
          onClick={() => pick('print')}
          data-testid={`${testIdPrefix}-row-menu-print`}
        >
          <i className="fas fa-print" aria-hidden />
          {labels.print}
        </button>
        <button
          type="button"
          className={styles.item}
          role="menuitem"
          onClick={() => pick('export')}
          data-testid={`${testIdPrefix}-row-menu-export`}
        >
          <i className="fas fa-file-excel" aria-hidden />
          {labels.export}
        </button>
        {canChart ? (
          <button
            type="button"
            className={styles.item}
            role="menuitem"
            onClick={() => pick('chart')}
            data-testid={`${testIdPrefix}-row-menu-chart`}
          >
            <i className="fas fa-chart-line" aria-hidden />
            {labels.chart}
          </button>
        ) : null}
      </div>
    </>,
    document.body,
  );
};
