import React, { useCallback, useMemo, useState } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import {
  dispatchAppToast,
  type ErpListRowEditHintState,
  type ErpListTableConfig,
  useViewMobileLayout,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../store/hooks';
import type { LedgerEntryDto } from '../../services/kt/models';
import { isRowEditHintDismissed } from '../../utils/erpListRowEditHintDismiss';
import { reportGridRowHintDismissStorageKey } from '../../utils/reportGridRowMenuHint';
import { formatAccountDisplay } from '../search/accountSearchApi';
import { formatDateLocal, formatVnd } from '../../utils/formatters';
import { canOpenReportDetailRow, openReportDetailView } from '../../utils/openReportDetailView';
import {
  canOpenSourceDocumentRow,
  openSourceDocumentView,
  resolveSourceDocumentViewUrl,
} from '../../utils/openSourceDocumentView';
import { resolveDocumentViewPath } from '../../utils/reportDocumentDrillDown';
import erp from '../../styles/erpPage.module.css';
import {
  ReportRowActionMenu,
  ReportSourceDocumentSlideout,
  type ReportRowMenuAction,
} from '../report';
import { triggerErpReportPrint } from '../../utils/triggerErpReportPrint';
import { exportLedgerRowsToExcel, formatLedgerExportFileName } from './exportLedgerExcel';
import {
  isReportGridMenuClickTrigger,
  isReportGridMenuContextMenuTrigger,
} from './reportGridMenuTrigger';
import { ReportGridRowHintLayer } from './ReportGridRowHintLayer';
import { useReportGridRowLongPress } from './useReportGridRowLongPress';
import rowStyles from './LedgerReportGrid.module.css';

export type LedgerReportGridLabels = {
  colNo?: string;
  colDate: string;
  colAccount?: string;
  colVoucher: string;
  colCounterAccount?: string;
  colDescription: string;
  colDebit: string;
  colCredit: string;
  colBalance?: string;
  colBalanceDebit?: string;
  colBalanceCredit?: string;
  rowMenuViewDocument: string;
  rowMenuViewReportDetail: string;
  rowMenuRefreshData: string;
  rowMenuPrint: string;
  rowMenuExport: string;
  rowMenuChart: string;
  slideoutTitle: string;
  slideoutClose: string;
  slideoutOpenFull: string;
  slideoutLoadError: string;
  exportSuccess: string;
  exportError: string;
  rowMenuHint: string;
  rowMenuHintTouch: string;
};

export type LedgerReportGridProps = {
  items: LedgerEntryDto[];
  labels: LedgerReportGridLabels;
  testIdPrefix: string;
  exportAccountCode: string;
  showBalance?: boolean;
  /** KT detail reports — frozen account column (default true when `labels.colAccount` set). */
  showAccountColumn?: boolean;
  reportTitle?: string;
  onRefresh: () => void;
  /** Toolbar + row menu In — defaults to window.print(). */
  onPrint?: () => void;
  /** Row menu + toolbar Xem biểu đồ. */
  onChart?: () => void;
  /** Ẩn mục «Xem biểu đồ» row menu khi false — sync `reportToolbar.canChart` / `ErpReportDisplayConfig.chart`. */
  canChart?: boolean;
  /** Drill-down sang báo cáo chi tiết — menu hiện khi BE `canOpenDetailView` trên dòng. */
  canViewReportDetail?: boolean;
  /** Tab title báo cáo đích (vd. Sổ chi tiết). */
  detailReportTitle?: string;
  tableConfig?: Partial<ErpListTableConfig>;
  /** Parity `getRowEditBlockedMessage` — hint copy on row click. */
  getRowMenuHintMessage?: (row: LedgerEntryDto) => string | undefined;
  /** localStorage key for "Tôi đã hiểu" — default `${testIdPrefix}-row-menu-hint-understood`. Pass `null` to disable. */
  rowMenuHintDismissStorageKey?: string | null;
  /** STT offset — parity `ErpDataListGrid` / voucher list. Default page=1, pageSize=items.length. */
  page?: number;
  pageSize?: number;
  /** Default true — first column STT. */
  showSttColumn?: boolean;
};

function reportGridRowNo(index: number, page: number, pageSize: number): number {
  if (pageSize <= 0) return index + 1;
  return (page - 1) * pageSize + index + 1;
}

export const LedgerReportGrid: React.FC<LedgerReportGridProps> = ({
  items,
  labels,
  testIdPrefix,
  exportAccountCode,
  showBalance = true,
  showAccountColumn,
  reportTitle,
  onRefresh,
  onPrint,
  onChart,
  canChart = false,
  canViewReportDetail = false,
  detailReportTitle,
  tableConfig,
  getRowMenuHintMessage: getRowMenuHintMessageProp,
  rowMenuHintDismissStorageKey: rowMenuHintDismissStorageKeyProp,
  page = 1,
  pageSize: pageSizeProp,
  showSttColumn = true,
}) => {
  const dispatch = useAppDispatch();
  const navigate = useNavigate();
  const location = useLocation();
  const viewMobile = useViewMobileLayout();
  const [menu, setMenu] = useState<{ x: number; y: number; row: LedgerEntryDto } | null>(null);
  const [slideout, setSlideout] = useState<LedgerEntryDto | null>(null);
  const [rowMenuHint, setRowMenuHint] = useState<ErpListRowEditHintState | null>(null);

  const defaultHintMessage = viewMobile ? labels.rowMenuHintTouch : labels.rowMenuHint;
  const getRowMenuHintMessage = useCallback(
    (row: LedgerEntryDto) => {
      if (getRowMenuHintMessageProp) return getRowMenuHintMessageProp(row);
      return defaultHintMessage;
    },
    [getRowMenuHintMessageProp, defaultHintMessage],
  );

  const hintDismissStorageKey = useMemo(() => {
    if (rowMenuHintDismissStorageKeyProp === null) return undefined;
    if (rowMenuHintDismissStorageKeyProp) return rowMenuHintDismissStorageKeyProp;
    return reportGridRowHintDismissStorageKey(testIdPrefix);
  }, [rowMenuHintDismissStorageKeyProp, testIdPrefix]);

  const menuLabels = {
    viewDocument: labels.rowMenuViewDocument,
    viewReportDetail: labels.rowMenuViewReportDetail,
    refreshData: labels.rowMenuRefreshData,
    print: labels.rowMenuPrint,
    export: labels.rowMenuExport,
    chart: labels.rowMenuChart,
  };

  const openSlideoutForRow = useCallback((row: LedgerEntryDto) => {
    if (!canOpenSourceDocumentRow(row) || !row.sourceDocumentType || !row.sourceDocumentId) return;
    if (!resolveDocumentViewPath(row.sourceDocumentType, row.sourceDocumentId)) return;
    setSlideout(row);
  }, []);

  const openFullPageForRow = useCallback((row: LedgerEntryDto) => {
    const path = resolveSourceDocumentViewUrl(row);
    if (!path) return;
    openSourceDocumentView({
      sourceDocumentViewUrl: path,
      title: row.voucherCode || path,
      returnPath: location.pathname + location.search,
      returnTitle: reportTitle,
      documentType: row.sourceDocumentType ?? undefined,
      navigate,
    });
    setSlideout(null);
  }, [navigate, location.pathname, location.search, reportTitle]);

  const handleMenuSelect = useCallback((action: ReportRowMenuAction) => {
    const row = menu?.row;
    if (!row) return;
    switch (action) {
      case 'viewDocument':
        openSlideoutForRow(row);
        break;
      case 'viewReportDetail':
        if (canOpenReportDetailRow(row) && detailReportTitle) {
          openReportDetailView({
            detailViewUrl: row.detailViewUrl!,
            detailReportTitle,
            returnPath: location.pathname + location.search,
            returnTitle: reportTitle,
            navigate,
          });
        }
        break;
      case 'refreshData':
        onRefresh();
        break;
      case 'print':
        (onPrint ?? triggerErpReportPrint)();
        break;
      case 'export':
        try {
          exportLedgerRowsToExcel(items, formatLedgerExportFileName(exportAccountCode), {
            date: labels.colDate,
            account: labels.colAccount,
            voucher: labels.colVoucher,
            counterAccount: labels.colCounterAccount,
            description: labels.colDescription,
            debit: labels.colDebit,
            credit: labels.colCredit,
            balanceDebit: labels.colBalanceDebit,
            balanceCredit: labels.colBalanceCredit,
            balance: labels.colBalance,
          });
          dispatchAppToast(dispatch, { message: labels.exportSuccess, type: 'success' });
        } catch {
          dispatchAppToast(dispatch, { message: labels.exportError, type: 'error' });
        }
        break;
      case 'chart':
        onChart?.();
        break;
      default:
        break;
    }
  }, [menu?.row, openSlideoutForRow, detailReportTitle, navigate, location.pathname, location.search, reportTitle, onRefresh, onPrint, onChart, items, exportAccountCode, labels, dispatch]);

  const openRowMenu = useCallback(
    (x: number, y: number, row: LedgerEntryDto) => {
      setRowMenuHint(null);
      setMenu({ x, y, row });
    },
    [],
  );

  const longPress = useReportGridRowLongPress<LedgerEntryDto>({
    enabled: true,
    onLongPress: ({ row, x, y }) => openRowMenu(x, y, row),
  });

  const handleRowClick = useCallback(
    (e: React.MouseEvent, row: LedgerEntryDto) => {
      if (longPress.consumeClickAfterLongPress()) return;
      if (isReportGridMenuClickTrigger(e)) {
        e.preventDefault();
        e.stopPropagation();
        openRowMenu(e.clientX, e.clientY, row);
        return;
      }
      const hintMessage = getRowMenuHintMessage(row);
      if (hintMessage) {
        if (!hintDismissStorageKey || !isRowEditHintDismissed(hintDismissStorageKey)) {
          setRowMenuHint({ x: e.clientX, y: e.clientY, message: hintMessage });
        }
      } else {
        setRowMenuHint(null);
      }
    },
    [longPress, openRowMenu, getRowMenuHintMessage, hintDismissStorageKey],
  );

  const handleRowDoubleClick = useCallback(
    (e: React.MouseEvent, row: LedgerEntryDto) => {
      const target = e.target as HTMLElement;
      if (target.closest('input, button, a, [role="button"]')) return;
      openRowMenu(e.clientX, e.clientY, row);
    },
    [openRowMenu],
  );

  const handleRowContextMenu = useCallback(
    (e: React.MouseEvent, row: LedgerEntryDto) => {
      if (!isReportGridMenuContextMenuTrigger(e)) return;
      const target = e.target as HTMLElement;
      if (target.closest('input, button, a, [role="button"]')) return;
      e.preventDefault();
      e.stopPropagation();
      openRowMenu(e.clientX, e.clientY, row);
    },
    [openRowMenu],
  );

  if (items.length === 0) return null;

  const pageSize = pageSizeProp ?? items.length;
  const sttHeader = labels.colNo ?? 'STT';
  const showAccount = showAccountColumn ?? Boolean(labels.colAccount);
  const showCounterAccount = Boolean(labels.colCounterAccount);

  const tableWrapperClass = [
    erp.tableWrapper,
    tableConfig?.stickyHeader ? erp.tableWrapperStickyHead : '',
    tableConfig?.heightMode === 'fixed' && tableConfig.height ? erp.tableWrapperHeightFixed : '',
  ].filter(Boolean).join(' ');

  const tableWrapperStyle: React.CSSProperties | undefined =
    tableConfig?.heightMode === 'fixed' && tableConfig.height
      ? { maxHeight: tableConfig.height, height: tableConfig.height }
      : undefined;

  return (
    <>
      <div className={tableWrapperClass} style={tableWrapperStyle} data-lin-erp-data-grid>
        <table className={erp.table}>
          <thead>
            <tr>
              {showSttColumn ? <th className={erp.colNo}>{sttHeader}</th> : null}
              <th>{labels.colDate}</th>
              {showAccount && labels.colAccount ? (
                <th data-lin-report-account-col>{labels.colAccount}</th>
              ) : null}
              <th>{labels.colVoucher}</th>
              {showCounterAccount ? (
                <th data-lin-report-counter-account-col>{labels.colCounterAccount}</th>
              ) : null}
              <th>{labels.colDescription}</th>
              <th className={erp.colRight}>{labels.colDebit}</th>
              <th className={erp.colRight}>{labels.colCredit}</th>
              {showBalance && (labels.colBalanceDebit || labels.colBalanceCredit) && (
                <>
                  <th className={erp.colRight}>{labels.colBalanceDebit ?? 'Dư Nợ'}</th>
                  <th className={erp.colRight}>{labels.colBalanceCredit ?? 'Dư Có'}</th>
                </>
              )}
              {showBalance && labels.colBalance && !labels.colBalanceDebit && !labels.colBalanceCredit && (
                <th className={erp.colRight}>{labels.colBalance}</th>
              )}
            </tr>
          </thead>
          <tbody>
            {items.map((r, i) => {
              const isSynthetic = r.rowTag === 1 || r.rowTag === 2;
              const rowClass = [rowStyles.clickableRow, isSynthetic ? rowStyles.syntheticRow : ''].filter(Boolean).join(' ');
              return (
              <tr
                key={`${r.voucherCode}-${r.entryDate}-${r.rowTag ?? 0}-${i}`}
                className={rowClass}
                onClick={isSynthetic ? undefined : e => handleRowClick(e, r)}
                onDoubleClick={isSynthetic ? undefined : e => handleRowDoubleClick(e, r)}
                onContextMenu={isSynthetic ? undefined : e => handleRowContextMenu(e, r)}
                onPointerDown={isSynthetic ? undefined : e => longPress.onPointerDown(e, r)}
                onPointerMove={isSynthetic ? undefined : longPress.onPointerMove}
                onPointerUp={isSynthetic ? undefined : longPress.onPointerUp}
                onPointerCancel={isSynthetic ? undefined : longPress.onPointerCancel}
                data-testid={`${testIdPrefix}-row-${i}`}
                data-row-tag={r.rowTag ?? 0}
              >
                {showSttColumn ? (
                  <td className={erp.colNo} data-testid={`${testIdPrefix}-row-${i}-no`}>
                    {reportGridRowNo(i, page, pageSize)}
                  </td>
                ) : null}
                <td>{formatDateLocal(r.entryDate)}</td>
                {showAccount && labels.colAccount ? (
                  <td data-lin-report-account-col>
                    <code>{formatAccountDisplay(r.accountCode, r.accountName)}</code>
                  </td>
                ) : null}
                <td>{r.voucherCode ? <code>{r.voucherCode}</code> : null}</td>
                {showCounterAccount ? (
                  <td data-lin-report-counter-account-col>
                    {r.counterAccountCode ? (
                      <code>{formatAccountDisplay(r.counterAccountCode, r.counterAccountName)}</code>
                    ) : null}
                  </td>
                ) : null}
                <td>{r.description}</td>
                <td className={erp.colRight}>{formatVnd(r.debitAmount)}</td>
                <td className={erp.colRight}>{formatVnd(r.creditAmount)}</td>
                {showBalance && (labels.colBalanceDebit || labels.colBalanceCredit) && (
                  <>
                    <td className={erp.colRight}>{formatVnd(r.balanceDebit ?? 0)}</td>
                    <td className={erp.colRight}>{formatVnd(r.balanceCredit ?? 0)}</td>
                  </>
                )}
                {showBalance && labels.colBalance && !labels.colBalanceDebit && !labels.colBalanceCredit && (
                  <td className={erp.colRight}>{formatVnd(r.runningBalance)}</td>
                )}
              </tr>
            );
            })}
          </tbody>
        </table>
      </div>

      <ReportRowActionMenu
        open={menu != null}
        x={menu?.x ?? 0}
        y={menu?.y ?? 0}
        onClose={() => setMenu(null)}
        onSelect={handleMenuSelect}
        labels={menuLabels}
        canOpenDocument={canOpenSourceDocumentRow(menu?.row) && Boolean(
          menu?.row.sourceDocumentType
          && menu?.row.sourceDocumentId
          && resolveDocumentViewPath(menu.row.sourceDocumentType, menu.row.sourceDocumentId),
        )}
        canViewReportDetail={canViewReportDetail && canOpenReportDetailRow(menu?.row)}
        canChart={canChart}
        testIdPrefix={testIdPrefix}
      />

      <ReportSourceDocumentSlideout
        isOpen={slideout != null}
        onClose={() => setSlideout(null)}
        documentType={slideout?.sourceDocumentType ?? null}
        documentId={slideout?.sourceDocumentId ?? null}
        voucherCode={slideout?.voucherCode}
        title={labels.slideoutTitle}
        closeLabel={labels.slideoutClose}
        openFullLabel={labels.slideoutOpenFull}
        loadErrorLabel={labels.slideoutLoadError}
        onOpenFullPage={() => slideout && openFullPageForRow(slideout)}
        testIdPrefix={testIdPrefix}
      />

      <ReportGridRowHintLayer
        hint={rowMenuHint}
        dismissStorageKey={hintDismissStorageKey}
        onDismiss={() => setRowMenuHint(null)}
      />
    </>
  );
};

