import React from 'react';
import styles from './ReportPrintSummary.module.css';

export type ReportPrintFilterLine = {
  label: string;
  value: string;
};

export type ReportPrintSummaryProps = {
  title: string;
  filters: ReportPrintFilterLine[];
  testIdPrefix: string;
  className?: string;
};

/**
 * Print-only report header — parity `LinReportPrintSummary` (common-components).
 * Migrate import when MFE upgrades `@linm-soft-org/linm-web-common-components`.
 */
export const ReportPrintSummary: React.FC<ReportPrintSummaryProps> = ({
  title,
  filters,
  testIdPrefix,
  className,
}) => (
  <div
    className={[styles.root, className].filter(Boolean).join(' ')}
    data-lin-report-print-summary
    data-testid={`${testIdPrefix}-print-summary`}
    aria-hidden
  >
    <h2 className={styles.title} data-testid={`${testIdPrefix}-print-title`}>
      {title}
    </h2>
    {filters.length > 0 ? (
      <ul className={styles.filters} data-testid={`${testIdPrefix}-print-filter-lines`}>
        {filters.map((line, i) => (
          <li key={`${line.label}-${i}`} className={styles.filterRow}>
            <span className={styles.filterLabel}>{line.label}: </span>
            <span>{line.value}</span>
          </li>
        ))}
      </ul>
    ) : null}
  </div>
);
