import { useCallback, useRef } from 'react';

const LONG_PRESS_MS = 500;
const MOVE_TOLERANCE_PX = 10;

export type ReportGridLongPressPayload<T> = {
  row: T;
  x: number;
  y: number;
};

export function useReportGridRowLongPress<T>(options: {
  enabled: boolean;
  onLongPress: (payload: ReportGridLongPressPayload<T>) => void;
}) {
  const { enabled, onLongPress } = options;
  const timerRef = useRef<number | null>(null);
  const startRef = useRef<{ x: number; y: number; row: T } | null>(null);
  const longPressFiredRef = useRef(false);

  const clearTimer = useCallback(() => {
    if (timerRef.current != null) window.clearTimeout(timerRef.current);
    timerRef.current = null;
    startRef.current = null;
  }, []);

  const onPointerDown = useCallback(
    (e: React.PointerEvent, row: T) => {
      if (!enabled) return;
      longPressFiredRef.current = false;
      clearTimer();
      startRef.current = { x: e.clientX, y: e.clientY, row };
      timerRef.current = window.setTimeout(() => {
        const start = startRef.current;
        if (!start) return;
        longPressFiredRef.current = true;
        onLongPress({ row: start.row, x: start.x, y: start.y });
        clearTimer();
      }, LONG_PRESS_MS);
    },
    [enabled, onLongPress, clearTimer],
  );

  const onPointerMove = useCallback(
    (e: React.PointerEvent) => {
      const start = startRef.current;
      if (!start) return;
      const dx = e.clientX - start.x;
      const dy = e.clientY - start.y;
      if (Math.hypot(dx, dy) > MOVE_TOLERANCE_PX) clearTimer();
    },
    [clearTimer],
  );

  const onPointerUp = useCallback(() => {
    clearTimer();
  }, [clearTimer]);

  const onPointerCancel = useCallback(() => {
    clearTimer();
  }, [clearTimer]);

  /** Suppress synthetic click after long-press opened the menu. */
  const consumeClickAfterLongPress = useCallback((): boolean => {
    if (!longPressFiredRef.current) return false;
    longPressFiredRef.current = false;
    return true;
  }, []);

  return {
    onPointerDown,
    onPointerMove,
    onPointerUp,
    onPointerCancel,
    consumeClickAfterLongPress,
  };
}
